                f.write(f"RUNS = {runs}\n")
                f.write(f"TIME_LIMIT = {int(time_limit)}\n")
                f.write(f"TRACE_LEVEL = 0\n")
                f.write(f"SEED = 42\n")

            remaining = 8.8 - (time.time() - t0)
            if remaining < 1:
                return None

            proc = subprocess.run(
                [lkh_bin, par_file],
                capture_output=True,
                timeout=remaining + 1,
                cwd=tmpdir
            )

            if not os.path.exists(tour_file):
                return None

            with open(tour_file, 'r') as f:
                content = f.read()

            tour = parse_lkh_tour(content, n)
            return tour

    except Exception:
        return None


def parse_lkh_tour(content, n):
    lines = content.strip().split('\n')
    in_tour = False
    nodes = []
    for line in lines:
        line = line.strip()
        if line == "TOUR_SECTION":
            in_tour = True
            continue
        if in_tour:
            if line == "-1" or line == "EOF":
                break
            try:
                nodes.append(int(line) - 1)
            except ValueError:
                continue

    if len(nodes) == n:
        return nodes
    return None


def fallback_solve(cities, t0):
    n = len(cities)
    budget = 9.0

    def dist(i, j):
        dx = cities[i][0] - cities[j][0]
        dy = cities[i][1] - cities[j][1]
        return int(math.sqrt(dx*dx + dy*dy) + 0.5)

    if n <= 600:
        d = [[0]*n for _ in range(n)]
        for i in range(n):
