                v = dist(i, j)
                d[i][j] = v
                d[j][i] = v
        def D(i, j): return d[i][j]
    else:
        def D(i, j): return dist(i, j)

    def nn_tour(start):
        visited = [False]*n
        tour = [start]
        visited[start] = True
        for _ in range(n-1):
            cur = tour[-1]
            best_d = float('inf')
            best_j = -1
            for j in range(n):
                if not visited[j] and D(cur, j) < best_d:
                    best_d = D(cur, j)
                    best_j = j
            tour.append(best_j)
            visited[best_j] = True
        return tour

    def tour_length(tour):
        return sum(D(tour[i], tour[(i+1)%n]) for i in range(n))

    k = min(10, n-1)
    candidates = []
    for i in range(n):
        dists = [(D(i,j), j) for j in range(n) if j != i]
        dists.sort()
        candidates.append([j for _, j in dists[:k]])

    def two_opt(tour):
        improved = True
        pos = [0]*n
        for i, c in enumerate(tour):
            pos[c] = i
        while improved and time.time()-t0 < budget-1.0:
            improved = False
            for idx in range(n):
                i = tour[idx]
                i_next = tour[(idx+1)%n]
                for j in candidates[i]:
                    jdx = pos[j]
                    j_next = tour[(jdx+1)%n]
                    if j == i_next or j_next == i:
                        continue
                    old = D(i, i_next) + D(j, j_next)
                    new = D(i, j) + D(i_next, j_next)
                    if new < old - 1e-10:
                        a, b = (idx+1)%n, jdx
                        if a <= b:
                            seg = tour[a:b+1]
                            seg.reverse()
                            tour[a:b+1] = seg
                        else:
                            combined = tour[a:] + tour[:b+1]
                            combined.reverse()
                            tour[a:] = combined[:n-a]
                            tour[:b+1] = combined[n-a:]
                        for k2, c in enumerate(tour):
                            pos[c] = k2
                        improved = True
                        break
        return tour

    def or_opt1(tour):
        improved = True
        pos = [0]*n
        for i, c in enumerate(tour):
            pos[c] = i
        while improved and time.time()-t0 < budget-0.3:
            improved = False
            for idx in range(n):
